"use strict";(self.webpackChunklindb_doc=self.webpackChunklindb_doc||[]).push([[5868],{3712:(t,e,a)=>{a.r(e),a.d(e,{default:()=>u});var r=a(6252),d=a(5829);const i=(0,r.uE)('<h1 id="索引" tabindex="-1"><a class="header-anchor" href="#索引" aria-hidden="true">#</a> 索引</h1><p>主要作用是为方便对某个 Metric 下面 Tags 的 Filtering/Grouping 操作，同时也是为了提升整体的查询效率。</p><p>整个索引为一个倒排结构，类似 Lucene ，但是相比会更加简单，因为在时序这样的场景不需要做分词这样的操作。</p><h2 id="结构" tabindex="-1"><a class="header-anchor" href="#结构" aria-hidden="true">#</a> 结构</h2><h3 id="metadata" tabindex="-1"><a class="header-anchor" href="#metadata" aria-hidden="true">#</a> Metadata</h3><p>主要存储 string-&gt;uint32 数据转换，类似经典的 OpenTSDB 设计思想。</p><h4 id="namespace" tabindex="-1"><a class="header-anchor" href="#namespace" aria-hidden="true">#</a> Namespace</h4><table><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Namespace(string value)</td><td>Namespace ID(uint32)</td></tr></tbody></table><h4 id="metric" tabindex="-1"><a class="header-anchor" href="#metric" aria-hidden="true">#</a> Metric</h4><table><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Namespace ID + Metric Name(string value)</td><td>Metric ID(uint32)</td></tr></tbody></table><h4 id="field" tabindex="-1"><a class="header-anchor" href="#field" aria-hidden="true">#</a> Field</h4><table><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Metric ID</td><td>Field List</td></tr></tbody></table><div class="language-yaml" data-ext="yml"><pre class="language-yaml"><code>单个 Field 的结构如下：\n<span class="token key atrule">Field ID</span><span class="token punctuation">:</span> 在该 Metric 下是唯一的，存储数据的时候用该 ID\n<span class="token key atrule">Field Name</span><span class="token punctuation">:</span> 字段名\n<span class="token key atrule">Field Type</span><span class="token punctuation">:</span> 字段类型，如 Sum/Min/Max 等\n</code></pre></div><h4 id="tag-key" tabindex="-1"><a class="header-anchor" href="#tag-key" aria-hidden="true">#</a> Tag key</h4><table><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Metric ID</td><td>Tag Key List</td></tr></tbody></table><div class="language-yaml" data-ext="yml"><pre class="language-yaml"><code>单个 Tag Key 的结构如下：\n<span class="token key atrule">Tag Key ID</span><span class="token punctuation">:</span> 在该 Database 下是唯一的，存储 Index 的时候用该 ID\n<span class="token key atrule">Tag Key</span> <span class="token punctuation">:</span> Tag Key(string value)\n</code></pre></div><h4 id="tag-value" tabindex="-1"><a class="header-anchor" href="#tag-value" aria-hidden="true">#</a> Tag value</h4><table><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Tag Key ID</td><td>Tag Values Trie</td></tr></tbody></table><p>其中 Tag Value 以 Trie 结构存储该 Tag Key 下所有的 Tag Value 的值，同时通过 Trie 的结构为每个 Tag Value 生成一个该 Tag Key 下唯一的 Tag Value ID 。</p><h3 id="index" tabindex="-1"><a class="header-anchor" href="#index" aria-hidden="true">#</a> Index</h3><p>由于在 Metadata 中已经做了 string-&gt;uint32 的操作，因此在 Index 中其实都是按数字来存储，进一步减少存储空间。</p><h4 id="forward" tabindex="-1"><a class="header-anchor" href="#forward" aria-hidden="true">#</a> Forward</h4><table><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Series IDs(Roaring Bitmap)</td><td>Tag Value IDs(Array)</td></tr></tbody></table><div class="custom-container tip"><p class="custom-container-title">提示</p><p>Forward Index 和传统的索引有所不同，传统索引会把每一条写入的数据当成一个正向记录存储下来，对应时序里面就是一条条的 Time Series 对应的 Tags，而这些 Tags 经过 Metadata 里面的 string-&gt;uint32 转换之后，都变成了一串数据，所以可以把这些数据都压缩到一条 Forward Index 中。</p></div><h4 id="inverted" tabindex="-1"><a class="header-anchor" href="#inverted" aria-hidden="true">#</a> Inverted</h4><table><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Tag Value ID</td><td>Series IDs(Roaring Bitmap)</td></tr></tbody></table><h2 id="查询" tabindex="-1"><a class="header-anchor" href="#查询" aria-hidden="true">#</a> 查询</h2><p>下面以一个例子的方式来说明 Filtering/Grouping 。</p><h3 id="filtering" tabindex="-1"><a class="header-anchor" href="#filtering" aria-hidden="true">#</a> Filtering</h3><p>如下表为一个 Metric(cpu) 下面 Tags 对应的正向数据，有 3 个 Tags 分别为 host/cpu/type</p><table><thead><tr><th>Tags</th><th>Series ID</th></tr></thead><tbody><tr><td>host=dev cpu=0 type=SCHED</td><td>1</td></tr><tr><td>host=dev cpu=1 type=SCHED</td><td>2</td></tr><tr><td>host=dev cpu=0 type=TIMER</td><td>3</td></tr><tr><td>host=dev cpu=1 type=TIMER</td><td>4</td></tr><tr><td>host=test cpu=0 type=SCHED</td><td>5</td></tr><tr><td>host=test cpu=1 type=SCHED</td><td>6</td></tr><tr><td>host=test cpu=2 type=SCHED</td><td>7</td></tr><tr><td>host=test cpu=3 type=SCHED</td><td>8</td></tr><tr><td>host=test cpu=0 type=TIMER</td><td>9</td></tr><tr><td>host=test cpu=1 type=TIMER</td><td>10</td></tr><tr><td>host=test cpu=2 type=TIMER</td><td>11</td></tr><tr><td>host=test cpu=3 type=TIMER</td><td>12</td></tr></tbody></table><p>如果把上表的数据，倒排一下，就形成了如下表的倒排结构，Posting List 直接用 Roaring Bitmap 来存储。</p><table><thead><tr><th>Tag</th><th>Posting List</th></tr></thead><tbody><tr><td>host=dev</td><td>1, 2, 3, 4</td></tr><tr><td>host=test</td><td>5, 6, 7, 8, 9, 10, 11, 12</td></tr><tr><td>cpu=0</td><td>1, 3, 5, 9</td></tr><tr><td>cpu=1</td><td>2, 4, 6, 10</td></tr><tr><td>cpu=2</td><td>7, 11</td></tr><tr><td>cpu=3</td><td>8, 12</td></tr><tr><td>type=SCHED</td><td>1, 2, 5, 6, 7, 8</td></tr><tr><td>type=TIMER</td><td>3, 4, 9, 10, 11, 12</td></tr></tbody></table><p>同时对 Tag 下面的 Tag Values 以前缀树的方式存储，以方便对 Tag Value 做过滤操作，如 host like dev* 这样的前缀过滤操作。加上上面的倒排结构之后，对于条件过滤操作就非常方便，如多个条件的操作只需要对多个 Posting List 做<strong>与</strong>/<strong>或</strong>操作即可，基本可以满足日常多个条件的 And/Or/Not 这样的过滤操作。</p><div class="custom-container tip"><p class="custom-container-title">提示</p><p>例如：</p><ul><li>Case 1: host = test or host = dev，就是 2 个 Posting list 的 ”与“ 操作</li><li>Case 1: host != test，这种就是找到 host 下面所的 Series IDs 和 host = test 的 Series IDs，把这 2 个 Posting list 求一个 AntNot(Difference) 操作即可</li></ul></div><p>同时基于这个倒排结构可能支持一些 Metadata 的查询，如想知道 host 这个 Tag 下面有哪些 Value 等。</p><h3 id="grouping" tabindex="-1"><a class="header-anchor" href="#grouping" aria-hidden="true">#</a> Grouping</h3><p>那么，如果不存储正向数据，怎么来解决按某个或者某几个 Tag Key 的 Group By 操作呢？如果我们像 Lucene 一样需要对 Tag Value 做分词的话，基本上是做不到通过反向来推导出正向的数据，但是在 TSDB 这样的场景里面，我们不需要对 Tag Value 做分词处理，所以还是可以通过反向的数据来反推出来正向的数据的。</p><p>如下图，已经把单条 Tag Key 的正向数据重新还原成 Tag Key/Value =&gt; Series IDs ，以方便理解。</p><p><img src="'+d+'" alt="index forward"></p><p>下面还是拿之前那个例子来说明，怎么来拿到 Group By host,cpu 这 2 个 Tag Key 的数据，如上图所示，其实从图中可以看到，整个操作就是一个归并操作，有 2 种做法。</p><ol><li>因为每个数据都是排好序的，所以可以用 2 个堆来排序，即 host 和 cpu 分别放在一个堆里面，每次从每个堆里面取一个值，如果值相同，说明 2 者都满足，如 TSID = 0 对应的 host=dev,cpu=0 ，即可以找到相应的 Group By 数据，以此类推，遍历完 2 个堆里面的数据，就可以得到最终的结合，该方式会占用 CPU ，内存占用少；</li><li>使用类似 Counting Sort ，即预先分配好一个固定大小的数组，然后把 Series IDs 放在相应的数组下标里面，如下标为 1 中同时包括了 2 个 Tag Key 的数据，即是我们想要的，以此类推，可以拿到所有的数据， CPU 占用少，但是浪费内存；</li></ol><p>再结合，Roaring Bitmap High/Low Container 的结构，一个 Container 里最多可以有 65536 个 uint16 值，所以内存的占用也可以得到控制，所以我们采用 Counting Sort 的方式来推导对应的正向数据，并且整体过程可以按一个个 Container 来并行处理。</p><h5 id="参考引用" tabindex="-1"><a class="header-anchor" href="#参考引用" aria-hidden="true">#</a> 参考引用</h5>',44),n={href:"http://roaringbitmap.org/",target:"_blank",rel:"noopener noreferrer"},l={href:"https://akumuli.org/akumuli/2017/11/17/indexing/",target:"_blank",rel:"noopener noreferrer"},s={href:"https://en.wikipedia.org/wiki/Counting_sort",target:"_blank",rel:"noopener noreferrer"},h={href:"https://en.wikipedia.org/wiki/Trie",target:"_blank",rel:"noopener noreferrer"},o={href:"https://en.wikipedia.org/wiki/Succinct_data_structure",target:"_blank",rel:"noopener noreferrer"},p={},u=(0,a(3744).Z)(p,[["render",function(t,e){const a=(0,r.up)("ExternalLinkIcon");return(0,r.wg)(),(0,r.iD)("div",null,[i,(0,r._)("ol",null,[(0,r._)("li",null,[(0,r._)("a",n,[(0,r.Uk)("RoaringBitmap"),(0,r.Wm)(a)])]),(0,r._)("li",null,[(0,r._)("a",l,[(0,r.Uk)("Akumuli Inverted Index"),(0,r.Wm)(a)])]),(0,r._)("li",null,[(0,r._)("a",s,[(0,r.Uk)("Counting Sort"),(0,r.Wm)(a)])]),(0,r._)("li",null,[(0,r._)("a",h,[(0,r.Uk)("Trie"),(0,r.Wm)(a)])]),(0,r._)("li",null,[(0,r._)("a",o,[(0,r.Uk)("Succinct Data Structure"),(0,r.Wm)(a)])])])])}]])},5829:(t,e,a)=>{t.exports=a.p+"assets/img/forward_grouping.8052c001.png"},75:(t,e,a)=>{a.r(e),a.d(e,{data:()=>r});const r=JSON.parse('{"key":"v-d24a98fa","path":"/zh/design/index_.html","title":"索引","lang":"zh-CN","frontmatter":{},"excerpt":"","headers":[{"level":2,"title":"结构","slug":"结构","link":"#结构","children":[{"level":3,"title":"Metadata","slug":"metadata","link":"#metadata","children":[{"level":4,"title":"Namespace","slug":"namespace","link":"#namespace","children":[]},{"level":4,"title":"Metric","slug":"metric","link":"#metric","children":[]},{"level":4,"title":"Field","slug":"field","link":"#field","children":[]},{"level":4,"title":"Tag key","slug":"tag-key","link":"#tag-key","children":[]},{"level":4,"title":"Tag value","slug":"tag-value","link":"#tag-value","children":[]}]},{"level":3,"title":"Index","slug":"index","link":"#index","children":[{"level":4,"title":"Forward","slug":"forward","link":"#forward","children":[]},{"level":4,"title":"Inverted","slug":"inverted","link":"#inverted","children":[]}]}]},{"level":2,"title":"查询","slug":"查询","link":"#查询","children":[{"level":3,"title":"Filtering","slug":"filtering","link":"#filtering","children":[]},{"level":3,"title":"Grouping","slug":"grouping","link":"#grouping","children":[]}]}],"git":{"updatedTime":1681286958000,"contributors":[{"name":"stone1100","email":"stonejh1100@gmail.com","commits":1}]},"filePathRelative":"zh/design/index_.md"}')}}]);